package com.chrisb97.warehouse.util;
import javafx.application.Platform;import javafx.scene.control.Alert;import javafx.scene.control.ButtonType;import java.util.Optional;
public final class AlertUtil{private AlertUtil(){}public static void info(String title,String message){show(Alert.AlertType.INFORMATION,title,message);}public static void error(String title,String message){show(Alert.AlertType.ERROR,title,message);}public static boolean confirm(String title,String message){Alert a=new Alert(Alert.AlertType.CONFIRMATION,message,ButtonType.YES,ButtonType.NO);a.setTitle(title);a.setHeaderText(null);return a.showAndWait().orElse(ButtonType.NO)==ButtonType.YES;}public static void showFatalError(String title,String message){Platform.runLater(()->show(Alert.AlertType.ERROR,title,message));}private static void show(Alert.AlertType type,String title,String message){Alert a=new Alert(type);a.setTitle(title);a.setHeaderText(null);a.setContentText(message);a.showAndWait();}}
